import { useRoutes, Navigate, useLocation } from "react-router-dom";
import { useState } from "react";
import classes from "./app.module.css";
import Home from "../components/pages/Home";
import Login from "../components/pages/Login";
import CalorieCalc from "../components/pages/CalorieCalc";
import Profile from "../components/pages/Profile";
import NavBar from "../components/navBar/NavBar";
import NotFound from "../components/pages/NotFound";

export default function App() {
  const location = useLocation();
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [currentUser, setCurrentUser] = useState(null);

  const RequireAuth = (element) => {
    return isLoggedIn ? element : <Navigate to="/" state={{ from: location }} replace />;
  };

  const handleLogin = (user) => {
    setIsLoggedIn(true);
    setCurrentUser(user);
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setCurrentUser(null);
  };

  const element = useRoutes([
    { path: "/", element: <Login onLoginSuccess={handleLogin} /> },
    {
      path: "/home",
      element: (
        <>
          <NavBar
            pages={[
              { name: "Login", path: "/" },
              { name: "Home", path: "/home" },
              { name: "CalorieCalculator", path: "/CalorieCalc" },
              { name: "Profile", path: "/profile" },
            ]}
            isLoggedIn={isLoggedIn}
            onLogout={handleLogout}
            currentUser={currentUser}
          />
          {RequireAuth(<Home />)}
        </>
      ),
    },
    {
      path: "/CalorieCalc",
      element: (
        <>
          <NavBar
            pages={[
              { name: "Login", path: "/" },
              { name: "Home", path: "/home" },
              { name: "CalorieCalculator", path: "/CalorieCalc" },
              { name: "Profile", path: "/profile" },
            ]}
            isLoggedIn={isLoggedIn}
            onLogout={handleLogout}
            currentUser={currentUser}
          />
          {RequireAuth(<CalorieCalc />)}
        </>
      ),
    },
    {
      path: "/profile",
      element: (
        <>
          <NavBar
            pages={[
              { name: "Login", path: "/" },
              { name: "Home", path: "/home" },
              { name: "CalorieCalculator", path: "/CalorieCalc" },
              { name: "Profile", path: "/profile" },
            ]}
            isLoggedIn={isLoggedIn}
            onLogout={handleLogout}
            currentUser={currentUser}
          />
          {RequireAuth(<Profile currentUser={currentUser} />)}
        </>
      ),
    },
    { path: "*", element: <NotFound /> },
  ]);

  return <section className={classes.app}>{element}</section>;
}
